{
    //Receiver's Number will come here
    "receivers": [
        "919999999999,919999999998"
    ],
    "title": "{{YOUR Campaign Title}}",
    //Channel ID*
    "channel": "{{YOUR CHANNEL ID}}",
    //Action can be -  'create','trigger' (Optional) [Default:'create']
    "action": "trigger",
    //Action can be -  'immediate','schedule' (Optional) [Default:'immediate']
    "mode":"immediate",
    //Schedule timestamp in milliseconds or ISO String (Optional) [Default]
    "schedule":0,
    //Array of messages's JSON
    "messages": [
        //messages
        {
            "type": "template",
            "template": {
                "language": {
                    "policy": "deterministic",
                    "code": "en"
                },
                "name": "hi_alert",
                "components": [
                    {
                        "type": "body",
                        "parameters": [
                            {
                                "type": "text",
                                "text": "VARIABLE_TEXT"
                            }
                        ]
                    }
                ]
            }
        }
    ]
}

{
    //Receiver's Number will come here
    "receivers": [
        {
            "to":"919999999999",
            "variables":{
                "name":"WhatsApp User"
            }
        }
    ],
    "title": "{{YOUR Campaign Title}}",
    //Channel ID*
    "channel": "{{YOUR CHANNEL ID}}",
    //Action can be -  'create','trigger' (Optional) [Default:'create']
    "action": "trigger",
    //Action can be -  'immediate','schedule' (Optional) [Default:'immediate']
    "mode":"immediate",
    //Schedule timestamp in milliseconds or ISO String (Optional) [Default]
    "schedule":0,
    //Array of messages's JSON
    "messages": [
        //messages
        {
            "type": "template",
            "template": {
                "language": {
                    "policy": "deterministic",
                    "code": "en"
                },
                "name": "hi_alert",
                "components": [
                    {
                        "type": "body",
                        "parameters": [
                            {
                                "type": "text",
                                "text": "{{name}}"
                            }
                        ]
                    }
                ]
            }
        }
    ]
}

